// Sadə tip məhdudiyyəti
function getLength<T extends { length: number }>(item: T): number {
  return item.length;
}

console.log(getLength('Hello')); // 5
console.log(getLength([1, 2, 3])); // 3
// console.log(getLength(42)); // Xəta: 42 length xüsusiyyətinə malik deyil

// Generic sinifdə tip məhdudiyyəti
class LengthBox<T extends { length: number }> {
  content: T;
  constructor(content: T) {
    this.content = content;
  }
  getLength(): number {
    return this.content.length;
  }
}

let stringBox = new LengthBox<string>('Hello');
let arrayBox = new LengthBox<number[]>([1, 2, 3]);

console.log(stringBox.getLength()); // 5
console.log(arrayBox.getLength()); // 3
// let errorBox = new LengthBox<number>(42); // Xəta: 42 length xüsusiyyətinə malik deyil

// Generic funksiyada tip məhdudiyyəti
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

let person = { name: 'Alice', age: 30 };
console.log(getProperty(person, 'name')); // Alice
console.log(getProperty(person, 'age')); // 30
// console.log(getProperty(person, 'address')); // Xəta: 'address' mövcud deyil

// Generic interfeysdə tip məhdudiyyəti
interface Printable<T extends { toString(): string }> {
  item: T;
  print(): string;
}

class Printer<T extends { toString(): string }> implements Printable<T> {
  item: T;
  constructor(item: T) {
    this.item = item;
  }
  print(): string {
    return this.item.toString();
  }
}

let stringPrinter = new Printer<string>('Hello');
let numberPrinter = new Printer<number>(42);

console.log(stringPrinter.print()); // Hello
console.log(numberPrinter.print()); // 42
// let errorPrinter = new Printer<{ name: string }>({ name: 'Test' }); // Xəta: toString() metodu yoxdur

